             {
                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
             }
             Course course = db.Courses.Include(c => c.Department).Where(c => c.CourseID == id).Single();
             if (course == null)
             {
                 return NotFound();
             }
             return View(course);
         }

