using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.Equal(2, list.PageIndex);
    }

    [Fact]
    public void Constructor_CalculatesTotalPages_RoundsUp()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_CalculatesTotalPages_ExactDivision()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 9, 1, 3);

        // Assert
        Assert.Equal(3, list.TotalPages); // ceil(9/3) = 3
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var list = new PaginatedList<int>(items, 10, 1, 3);

        // Assert
        Assert.Equal(3, list.Count);
        Assert.Contains(1, list);
        Assert.Contains(2, list);
        Assert.Contains(3, list);
    }

    [Theory]
    [InlineData(1, false)]
    [InlineData(2, true)]
    [InlineData(3, true)]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Arrange
        var items = new List<string> { "a" };
        var list = new PaginatedList<string>(items, 30, pageIndex, 10);

        // Act & Assert
        Assert.Equal(expected, list.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 3, true)]
    [InlineData(2, 3, true)]
    [InlineData(3, 3, false)]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        // Arrange
        var items = new List<string> { "a" };
        // totalPages = ceil(count/pageSize), we need count = totalPages * pageSize
        var list = new PaginatedList<string>(items, totalPages * 10, pageIndex, 10);

        // Act & Assert
        Assert.Equal(expected, list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(5, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // Second page starts at item 11
        Assert.Equal(20, result[9]); // Second page ends at item 20
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.Equal(3, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(5, result.Count); // Only 5 items on the last page
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Empty(result);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(0, result.TotalPages);
    }

    [Fact]
    public void Create_SingleItem_SinglePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Single(result);
        Assert.Equal(42, result[0]);
        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Constructor_ZeroCount_ZeroTotalPages()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);

        // Assert
        Assert.Equal(0, list.TotalPages);
        Assert.False(list.HasNextPage);
        Assert.False(list.HasPreviousPage);
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain any existing messages from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
        Assert.Contains("Student 'John Doe'", notification.Message);
        Assert.Contains("has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityId()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", null, EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Course (ID: 101)", notification.Message);
        Assert.Contains("has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "5", "Science", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_ShortOverload_WithoutDisplayName()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "10", EntityOperation.CREATE, "User1");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("10", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("User1", notification.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "has been created")]
    [InlineData(EntityOperation.UPDATE, "has been updated")]
    [InlineData(EntityOperation.DELETE, "has been deleted")]
    public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedPhrase)
    {
        // Arrange & Act
        _sut.SendNotification("Entity", "1", "TestEntity", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains(expectedPhrase, notification.Message);
    }

    [Fact]
    public void SendNotification_CreateOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "5", "Alice Smith", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("New Student 'Alice Smith' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("Course 'Math 101' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Arrange - queue is already empty from constructor

        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsInFIFOOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.Equal("A", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.Equal("B", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.Equal("C", third.EntityType);

        Assert.Null(_sut.ReceiveNotification()); // Queue is empty now
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
