        Assert.Equal("New Student 'Alice Smith' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("Course 'Math 101' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Arrange - queue is already empty from constructor

        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsInFIFOOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.Equal("A", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.Equal("B", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.Equal("C", third.EntityType);

        Assert.Null(_sut.ReceiveNotification()); // Queue is empty now
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
