+using System.Collections.Generic;
+using System.Linq;
+using ContosoUniversity;
+using Xunit;
+
+namespace ContosoUniversity.Tests;
+
+public class PaginatedListTests
+{
+    [Fact]
+    public void Constructor_SetsPageIndex()
+    {
+        // Arrange
+        var items = new List<string> { "a", "b", "c" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 10, 2, 3);
+
+        // Assert
+        Assert.Equal(2, list.PageIndex);
+    }
+
+    [Fact]
+    public void Constructor_CalculatesTotalPages_RoundsUp()
+    {
+        // Arrange
+        var items = new List<string> { "a", "b", "c" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 10, 1, 3);
+
+        // Assert
+        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
+    }
+
+    [Fact]
+    public void Constructor_CalculatesTotalPages_ExactDivision()
+    {
+        // Arrange
+        var items = new List<string> { "a", "b", "c" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 9, 1, 3);
+
+        // Assert
+        Assert.Equal(3, list.TotalPages); // ceil(9/3) = 3
+    }
+
+    [Fact]
+    public void Constructor_AddsItemsToList()
+    {
+        // Arrange
+        var items = new List<int> { 1, 2, 3 };
+
+        // Act
+        var list = new PaginatedList<int>(items, 10, 1, 3);
+
+        // Assert
+        Assert.Equal(3, list.Count);
+        Assert.Contains(1, list);
+        Assert.Contains(2, list);
+        Assert.Contains(3, list);
+    }
+
+    [Theory]
+    [InlineData(1, false)]
+    [InlineData(2, true)]
+    [InlineData(3, true)]
+    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
+    {
+        // Arrange
+        var items = new List<string> { "a" };
+        var list = new PaginatedList<string>(items, 30, pageIndex, 10);
+
+        // Act & Assert
+        Assert.Equal(expected, list.HasPreviousPage);
+    }
+
+    [Theory]
+    [InlineData(1, 3, true)]
+    [InlineData(2, 3, true)]
+    [InlineData(3, 3, false)]
+    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
+    {
+        // Arrange
+        var items = new List<string> { "a" };
+        // totalPages = ceil(count/pageSize), we need count = totalPages * pageSize
+        var list = new PaginatedList<string>(items, totalPages * 10, pageIndex, 10);
+
+        // Act & Assert
+        Assert.Equal(expected, list.HasNextPage);
+    }
+
+    [Fact]
+    public void Create_ReturnsCorrectPage()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 50).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 2, 10);
+
+        // Assert
+        Assert.Equal(2, result.PageIndex);
+        Assert.Equal(5, result.TotalPages);
+        Assert.Equal(10, result.Count);
+        Assert.Equal(11, result[0]); // Second page starts at item 11
+        Assert.Equal(20, result[9]); // Second page ends at item 20
+    }
+
+    [Fact]
+    public void Create_FirstPage_ReturnsFirstItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 25).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 1, 10);
+
+        // Assert
+        Assert.Equal(1, result.PageIndex);
+        Assert.Equal(3, result.TotalPages);
+        Assert.Equal(10, result.Count);
+        Assert.Equal(1, result[0]);
+        Assert.Equal(10, result[9]);
+    }
+
+    [Fact]
+    public void Create_LastPage_ReturnsRemainingItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 25).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 3, 10);
+
+        // Assert
+        Assert.Equal(3, result.PageIndex);
+        Assert.Equal(3, result.TotalPages);
+        Assert.Equal(5, result.Count); // Only 5 items on the last page
+        Assert.Equal(21, result[0]);
+        Assert.Equal(25, result[4]);
+    }
+
+    [Fact]
+    public void Create_EmptySource_ReturnsEmptyList()
+    {
+        // Arrange
+        var source = Enumerable.Empty<int>().AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 1, 10);
+
+        // Assert
+        Assert.Empty(result);
+        Assert.Equal(1, result.PageIndex);
+        Assert.Equal(0, result.TotalPages);
+    }
+
+    [Fact]
+    public void Create_SingleItem_SinglePage()
+    {
+        // Arrange
+        var source = new[] { 42 }.AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 1, 10);
+
+        // Assert
+        Assert.Single(result);
+        Assert.Equal(42, result[0]);
+        Assert.Equal(1, result.TotalPages);
+        Assert.False(result.HasPreviousPage);
+        Assert.False(result.HasNextPage);
+    }
+
+    [Fact]
+    public void Constructor_ZeroCount_ZeroTotalPages()
+    {
+        // Arrange & Act
+        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);
+
+        // Assert
+        Assert.Equal(0, list.TotalPages);
+        Assert.False(list.HasNextPage);
+        Assert.False(list.HasPreviousPage);
+    }
+}
+

