using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockLogger = new Mock<ILogger<CoursesController>>();

        _tempDir = Path.Combine(Path.GetTempPath(), $"contoso_test_{Guid.NewGuid()}");
        Directory.CreateDirectory(_tempDir);
        _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
        _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
    }

    private void SeedCoursesWithDepartment()
    {
        var department = new Department
        {
            Name = "Computer Science",
            Budget = 500000,
            StartDate = new DateTime(2000, 9, 1)
        };
        _context.Departments.Add(department);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = department.DepartmentID },
            new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = department.DepartmentID },
            new Course { CourseID = 3042, Title = "Literature", Credits = 4, DepartmentID = department.DepartmentID }
        );
        _context.SaveChanges();
    }

    #region Index Tests

    [Fact]
    public void Index_ReturnsViewWithAllCourses()
    {
        // Arrange
        SeedCoursesWithDepartment();

        // Act
        var result = _controller.Index();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Index_NoCourses_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Empty(model);
    }

    #endregion

    #region Details Tests

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedCoursesWithDepartment();

        // Act
        var result = _controller.Details(1050);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
        Assert.Equal(1050, model.CourseID);
    }

    #endregion

    #region Create Tests

    [Fact]
    public void Create_GET_ReturnsViewWithNewCourse()
    {
        // Arrange
        SeedCoursesWithDepartment();

        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.IsType<Course>(viewResult.Model);
    }

    [Fact]
    public void Create_POST_ValidCourse_NoFile_RedirectsToIndex()
    {
        // Arrange
        SeedCoursesWithDepartment();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 5001,
            Title = "New Course",
            Credits = 4,
            DepartmentID = dept.DepartmentID
        };

        // Act
        var result = _controller.Create(course, null);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidCourse_SavesToDB()
    {
        // Arrange
        SeedCoursesWithDepartment();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 5002,
            Title = "Saved Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        // Act
        _controller.Create(course, null);

        // Assert
        var saved = _context.Courses.Find(5002);
        Assert.NotNull(saved);
        Assert.Equal("Saved Course", saved.Title);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        SeedCoursesWithDepartment();
        var course = new Course { CourseID = 5003, Title = "Test", Credits = 3, DepartmentID = 1 };
        _controller.ModelState.AddModelError("Title", "Required");

        // Act
        var result = _controller.Create(course, null);

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Create_POST_WithValidImage_SavesFileAndRedirects()
    {
        // Arrange
        SeedCoursesWithDepartment();
        var dept = _context.Departments.First();
        var course = new Course
