using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedInstructorsWithCourses()
    {
        var department = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2000, 9, 1)
        };
        _context.Departments.Add(department);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1001, Title = "Calculus", Credits = 3, DepartmentID = department.DepartmentID, Enrollments = new List<Enrollment>() };
        var course2 = new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = department.DepartmentID, Enrollments = new List<Enrollment>() };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        var instructor1 = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" },
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1001 },
                new CourseAssignment { CourseID = 1002 }
            }
        };
        var instructor2 = new Instructor
        {
            LastName = "Harui",
            FirstMidName = "Roger",
            HireDate = new DateTime(1998, 7, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();
    }

    #region Index Tests

    [Fact]
    public void Index_NoParams_ReturnsViewWithAllInstructors()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Index(null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_SetsCourses()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First(i => i.LastName == "Fakhouri");

        // Act
        var result = _controller.Index(instructor.ID, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Equal(2, model.Courses.Count());
    }

    [Fact]
    public void Index_NoInstructors_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index(null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.Empty(model.Instructors);
    }

    #endregion

    #region Details Tests

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First();

        // Act
        var result = _controller.Details(instructor.ID);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal(instructor.LastName, model.LastName);
    }

    #endregion

    #region Create Tests

    [Fact]
    public void Create_GET_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
    }

    [Fact]
    public void Create_POST_ValidInstructor_NoCourses_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidInstructor_WithCourses_SavesCourseAssignments()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            LastName = "CourseInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };
        var selectedCourses = new[] { "1001", "1002" };

        // Act
        var result = _controller.Create(instructor, selectedCourses);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        var saved = _context.Instructors.Include(i => i.CourseAssignments)
            .FirstOrDefault(i => i.LastName == "CourseInstructor");
        Assert.NotNull(saved);
        Assert.Equal(2, saved.CourseAssignments.Count);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Test",
            FirstMidName = "Invalid",
            HireDate = new DateTime(2023, 1, 1)
        };
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    #endregion

    #region Delete Tests

    [Fact]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_GET_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First();

        // Act
        var result = _controller.Delete(instructor.ID);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal(instructor.LastName, model.LastName);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.LastName == "Fakhouri");

        // Act
        var result = _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Null(_context.Instructors.Find(instructor.ID));
    }

    [Fact]
    public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsDepartmentAdmin()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.LastName == "Fakhouri");

        // Make this instructor a department administrator
        var dept = _context.Departments.First();
        dept.InstructorID = instructor.ID;
        _context.SaveChanges();

        // Act
        _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.Null(updatedDept.InstructorID);
    }

    #endregion
}

