using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests : IDisposable
{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestDbContextFactory.Create();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void Context_CanAddAndRetrieveStudent()
    {
        // Arrange
        var student = new Student
        {
            LastName = "TestStudent",
            FirstMidName = "Integration",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        _context.Students.Add(student);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Students.FirstOrDefault(s => s.LastName == "TestStudent");
        Assert.NotNull(retrieved);
        Assert.Equal("Integration", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddAndRetrieveCourse()
    {
        // Arrange
        var dept = new Department { Name = "Test", Budget = 1000, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 9999, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID };

        // Act
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Courses.Find(9999);
        Assert.NotNull(retrieved);
        Assert.Equal("TestCourse", retrieved.Title);
    }

    [Fact]
    public void Context_CanAddAndRetrieveInstructor()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "TestInstructor",
            FirstMidName = "Data",
            HireDate = new DateTime(2015, 1, 1)
        };

        // Act
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Instructors.FirstOrDefault(i => i.LastName == "TestInstructor");
        Assert.NotNull(retrieved);
        Assert.Equal("Data", retrieved.FirstMidName);
    }

    [Fact]
    public void Context_CanAddAndRetrieveDepartment()
    {
        // Arrange
        var dept = new Department
        {
            Name = "NewDepartment",
            Budget = 250000,
            StartDate = new DateTime(2005, 9, 1)
        };

        // Act
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Departments.FirstOrDefault(d => d.Name == "NewDepartment");
        Assert.NotNull(retrieved);
        Assert.Equal(250000, retrieved.Budget);
    }

    [Fact]
    public void Context_CanAddAndRetrieveEnrollment()
    {
        // Arrange
        var student = new Student
        {
            LastName = "EnrollStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };
        _context.Students.Add(student);

        var dept = new Department { Name = "Dept", Budget = 1000, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 8888, Title = "EnrollCourse", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var enrollment = new Enrollment
        {
            StudentID = student.ID,
            CourseID = course.CourseID,
            Grade = Grade.B
        };

        // Act
        _context.Enrollments.Add(enrollment);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Enrollments.FirstOrDefault(e => e.StudentID == student.ID && e.CourseID == course.CourseID);
        Assert.NotNull(retrieved);
        Assert.Equal(Grade.B, retrieved.Grade);
    }

    [Fact]
    public void Context_CourseAssignment_HasCompositeKey()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "KeyTest",
            FirstMidName = "Composite",
            HireDate = new DateTime(2010, 1, 1)
        };
        _context.Instructors.Add(instructor);

        var dept = new Department { Name = "KeyDept", Budget = 1000, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 7777, Title = "KeyCourse", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var assignment = new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = course.CourseID
        };

        // Act
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.NotNull(retrieved);
    }

    [Fact]
    public void Context_InstructorWithOfficeAssignment_OneToOneRelationship()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "OfficeTest",
            FirstMidName = "Relation",
            HireDate = new DateTime(2010, 1, 1),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };

        // Act
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Instructors
            .Include(i => i.OfficeAssignment)
            .FirstOrDefault(i => i.LastName == "OfficeTest");
        Assert.NotNull(retrieved?.OfficeAssignment);
        Assert.Equal("Room 101", retrieved.OfficeAssignment.Location);
    }

    [Fact]
    public void Context_CanAddNotification()
    {
        // Arrange
        var notification = new Notification
        {
            EntityType = "Test",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        };

        // Act
        _context.Notifications.Add(notification);
        _context.SaveChanges();

        // Assert
        var retrieved = _context.Notifications.FirstOrDefault(n => n.EntityType == "Test");
        Assert.NotNull(retrieved);
        Assert.Equal("Test message", retrieved.Message);
    }
}

