using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain any existing messages from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _sut.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
        Assert.Contains("Student 'John Doe'", notification.Message);
        Assert.Contains("has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityId()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", null, EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Course (ID: 101)", notification.Message);
        Assert.Contains("has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "5", "Science", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_ShortOverload_WithoutDisplayName()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "10", EntityOperation.CREATE, "User1");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("10", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("User1", notification.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "has been created")]
    [InlineData(EntityOperation.UPDATE, "has been updated")]
    [InlineData(EntityOperation.DELETE, "has been deleted")]
    public void SendNotification_OperationTypes_GenerateCorrectMessages(EntityOperation operation, string expectedPhrase)
    {
        // Arrange & Act
        _sut.SendNotification("Entity", "1", "TestEntity", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains(expectedPhrase, notification.Message);
    }

    [Fact]
    public void SendNotification_CreateOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "5", "Alice Smith", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("New Student 'Alice Smith' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("Course 'Math 101' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_MessageFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Arrange - queue is already empty from constructor

        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsInFIFOOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.Equal("A", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.Equal("B", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.Equal("C", third.EntityType);

        Assert.Null(_sut.ReceiveNotification()); // Queue is empty now
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Test", "1", "Item", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now;
        var notification = _sut.ReceiveNotification();
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_SetsIsReadToFalse()
    {
        // Arrange & Act
        _sut.SendNotification("Test", "1", "Item", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Arrange & Act & Assert (no-op in current implementation)
        var exception = Record.Exception(() => _sut.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_EmptyDisplayName_UsesEntityIdFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.Contains("Student (ID: 42)", notification.Message);
    }

    [Fact]
    public void SendNotification_WhitespaceDisplayName_UsesEntityIdFormat()
