using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) },
            new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2021, 9, 1) }
        );
        _context.SaveChanges();
    }

    #region Index Tests

    [Fact]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(5, model.Count);
        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
    }

    [Fact]
    public void Index_NameDescSort_ReturnsDescendingByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("name_desc", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Li", model[0].LastName);
    }

    [Fact]
    public void Index_DateSort_ReturnsAscendingByEnrollmentDate()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("Date", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        // 2020 dates first
        Assert.Equal(new DateTime(2020, 9, 1), model[0].EnrollmentDate);
    }

    [Fact]
    public void Index_DateDescSort_ReturnsDescendingByEnrollmentDate()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("date_desc", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        // 2022 dates first
        Assert.Equal(new DateTime(2022, 9, 1), model[0].EnrollmentDate);
    }

    [Fact]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Li", null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Li", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_FiltersStudentsByFirstName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Carson", null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_ResetsPageTo1()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "A", 3);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex); // Reset to page 1 when searching
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, "Li", null, 1);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Li", model[0].LastName);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        // Arrange
        SeedStudents();

        // Act
        _controller.Index("Date", "test", null, 1);

        // Assert
        Assert.Equal("Date", (string)_controller.ViewBag.CurrentSort);
        Assert.Equal("date_desc", (string)_controller.ViewBag.DateSortParm);
        Assert.Equal("", (string)_controller.ViewBag.NameSortParm);
        Assert.Equal("test", (string)_controller.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Index_DefaultSort_SetsNameSortParmToNameDesc()
    {
        // Arrange
        SeedStudents();

        // Act
        _controller.Index(null, null, null, null);

        // Assert
        Assert.Equal("name_desc", (string)_controller.ViewBag.NameSortParm);
        Assert.Equal("Date", (string)_controller.ViewBag.DateSortParm);
    }

    #endregion

    #region Details Tests

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2023, 1, 1),
            Enrollments = new List<Enrollment>()
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(student.ID);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Smith", model.LastName);
        Assert.Equal("John", model.FirstMidName);
    }

    #endregion

    #region Create Tests

    [Fact]
    public void Create_GET_ReturnsViewWithStudentHavingTodaysDate()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    [Fact]
    public void Create_POST_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidStudent_SavesStudentToDatabase()
    {
        // Arrange
        var student = new Student
        {
            LastName = "SaveTest",
            FirstMidName = "Persistence",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        _controller.Create(student);

        // Assert
        var saved = _context.Students.FirstOrDefault(s => s.LastName == "SaveTest");
        Assert.NotNull(saved);
        Assert.Equal("Persistence", saved.FirstMidName);
    }

    [Fact]
    public void Create_POST_MinDateEnrollment_ReturnsViewWithError()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Same(student, viewResult.Model);
    }

    #endregion

    #region Edit Tests

    [Fact]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_GET_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_GET_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = new Student
        {
            LastName = "EditMe",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };
