        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("malware.exe");
        mockFile.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_POST_WithFileTooLarge_ReturnsViewWithError()
    {
        // Arrange
        SeedCoursesWithDepartment();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 5006,
            Title = "Large File",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("large.png");
        mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB > 5MB limit

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Theory]
    [InlineData(".jpg")]
    [InlineData(".jpeg")]
    [InlineData(".png")]
    [InlineData(".gif")]
    [InlineData(".bmp")]
    public void Create_POST_AcceptsValidImageExtensions(string extension)
    {
        // Arrange
        SeedCoursesWithDepartment();
