using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages_RoundsUp()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages_ExactDivision()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 9, 1, 3);

        // Assert
        Assert.AreEqual(3, list.TotalPages); // ceil(9/3) = 3
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var list = new PaginatedList<int>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.IsTrue(list.Contains(1));
        Assert.IsTrue(list.Contains(2));
        Assert.IsTrue(list.Contains(3));
    }

    [DataTestMethod]
    [DataRow(1, false)]
    [DataRow(2, true)]
    [DataRow(3, true)]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Arrange
        var items = new List<string> { "a" };
        var list = new PaginatedList<string>(items, 30, pageIndex, 10);

        // Act & Assert
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    [DataTestMethod]
    [DataRow(1, 3, true)]
    [DataRow(2, 3, true)]
    [DataRow(3, 3, false)]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        // Arrange
        var items = new List<string> { "a" };
        // totalPages = ceil(count/pageSize), we need count = totalPages * pageSize
        var list = new PaginatedList<string>(items, totalPages * 10, pageIndex, 10);

        // Act & Assert
        Assert.AreEqual(expected, list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(5, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]); // Second page starts at item 11
        Assert.AreEqual(20, result[9]); // Second page ends at item 20
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count); // Only 5 items on the last page
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count());
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
    }

    [TestMethod]
    public void Create_SingleItem_SinglePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.Count());
        Assert.AreEqual(42, result[0]);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Constructor_ZeroCount_ZeroTotalPages()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);

        // Assert
        Assert.AreEqual(0, list.TotalPages);
        Assert.IsFalse(list.HasNextPage);
        Assert.IsFalse(list.HasPreviousPage);
    }
