using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    private SchoolContext _context = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.Create();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(5, _context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(4, _context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(7, _context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(11, _context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(3, _context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicateData()
    {
        // Arrange - seed once
        DbInitializer.Initialize(_context);
        var studentCountAfterFirst = _context.Students.Count();

        // Act - seed again
        DbInitializer.Initialize(_context);

        // Assert - counts should remain the same
        Assert.AreEqual(studentCountAfterFirst, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_AlreadyHasStudents_ReturnsEarly()
    {
        // Arrange - add a single student manually
        _context.Students.Add(new Student
        {
            FirstMidName = "Existing",
            LastName = "Student",
            EnrollmentDate = new DateTime(2020, 1, 1)
        });
        _context.SaveChanges();

        // Act
        DbInitializer.Initialize(_context);

        // Assert - only the manually added student exists (seed was skipped)
        Assert.AreEqual(1, _context.Students.Count());
        Assert.AreEqual(0, _context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentNames()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.IsTrue(_context.Students.Any(s => s.LastName == "Alexander" && s.FirstMidName == "Carson"));
        Assert.IsTrue(_context.Students.Any(s => s.LastName == "Alonso" && s.FirstMidName == "Meredith"));
        Assert.IsTrue(_context.Students.Any(s => s.LastName == "Olivetto" && s.FirstMidName == "Nino"));
    }

    [TestMethod]
    public void Initialize_SeedsDepartmentsWithAdministrators()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var english = _context.Departments.FirstOrDefault(d => d.Name == "English");
        Assert.IsNotNull(english);
        Assert.IsNotNull(english.InstructorID);
        Assert.AreEqual(350000, english.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsCourseAssignmentsCorrectly()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - Chemistry should have 2 instructors
        var chemistryCourse = _context.Courses.First(c => c.Title == "Chemistry");
        var chemistryAssignments = _context.CourseAssignments.Where(ca => ca.CourseID == chemistryCourse.CourseID).Count();
        Assert.AreEqual(2, chemistryAssignments);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - Check that some enrollments have grades and some don't
        var withGrades = _context.Enrollments.Count(e => e.Grade != null);
        var withoutGrades = _context.Enrollments.Count(e => e.Grade == null);
        Assert.IsTrue(withGrades > 0);
        Assert.IsTrue(withoutGrades > 0);
    }
}

